UPDATE
T_BUS_TRUST_CARGO
SET
CONSIGNER_ID = #{consignerId,jdbcType=BIGINT},
CONSIGNER_NAME = #{consignerName,jdbcType=VARCHAR}

    ,QUANTITY = #{quantity,jdbcType=BIGINT},
    TON = #{ton,jdbcType=DECIMAL}


    id = #{id}

UPDATE T_BUS_TRUST_CARGO SET
CARGO_INFO_ID = #{cargoInfoId,jdbcType=BIGINT},
UPDATE_BY = #{loginUserId, jdbcType=BIGINT}, UPDATE_BY_NAME = #{loginUserName, jdbcType=VARCHAR}, UPDATE_TIME = #{now}
id = #{id}

mapper.select:
SELECT a.ID, a.TRUST_ID, a.CARGO_INFO_ID, a.DIRECTION, a.QUANTITY, a.TON, a.CARGO_OWNER_ID, a.CARGO_OWNER_NAME, a.CARGO_AGENT_ID, a.CARGO_AGENT_NAME, a.CARGO_CODE, CASE WHEN b.SIGN IS NOT NULL THEN a.CARGO_NAME || '(' || b.SIGN || ')' ELSE a.CARGO_NAME END AS "CARGO_NAME", a.PACKING_CODE, a.PACKING_NAME, a.CREATE_BY, a.CREATE_BY_NAME, a.CREATE_TIME, a.UPDATE_BY, a.UPDATE_BY_NAME, a.UPDATE_TIME, b.WORK_TYPE, a.CONTRACT_ID, a.CONTRACT_NAME, a.CONTRACT_RATE_ID, a.RATE, a.EST_AMOUNT, TBCI.CARGO_INFO_NO, TBCI.SHIPVOYAGE_ITEM_ID, case when tbt.type = '疏港' or tbt.type='装船' then a.delivery_numbers when RELEASE.DELIVERY_NUMBERS is null then a.DELIVERY_NUMBERS else RELEASE.DELIVERY_NUMBERS end as DELIVERY_NUMBERS, DISPATCH.PERMIT_THROUGH, a.BUSINESS_NO, a.HATCHS, a.IS_SECOND_WEIGH, a.PRINT_POUND_ID, a.PRINT_POUND_NUM, a.RATE_LABEL, a.CONSIGNER_ID, a.CONSIGNER_NAME, a.IS_STOP, a.IS_STOP_OPERATION_NAME, a.IS_STOP_OPERATION_TIME, a.DIS_RATE, a.ORDER_ITEM_ID, a.BILL_NO FROM T_BUS_TRUST_CARGO a inner join m_cargo b on a.CARGO_CODE=b.CARGO_CODE LEFT JOIN T_BUS_CARGO_INFO TBCI ON a.CARGO_INFO_ID = TBCI.ID left join t_bus_trust tbt on a.trust_id = tbt.id LEFT JOIN ( SELECT CARGO_INFO_NO, LISTAGG(DELIVERY_NUMBERS, ', ') WITHIN GROUP ( ORDER BY CARGO_INFO_NO) AS DELIVERY_NUMBERS FROM T_BUS_DISPATCH_RELEASE_DETAIL GROUP BY CARGO_INFO_NO ) RELEASE ON TBCI.CARGO_INFO_NO = RELEASE.CARGO_INFO_NO LEFT JOIN ( SELECT B.CARGO_INFO_NO, CASE WHEN COUNT(0) = SUM(TO_NUMBER(A.PERMIT_THROUGH)) THEN '放行' WHEN 0 = SUM(TO_NUMBER(A.PERMIT_THROUGH)) THEN '不放行' ELSE '部分放行' END AS PERMIT_THROUGH FROM T_BUS_DISPATCH_RELEASE A LEFT JOIN T_BUS_DISPATCH_RELEASE_DETAIL B ON A.ID = B.DISPATCH_RELEASE_ID GROUP BY B.CARGO_INFO_NO ) DISPATCH ON DISPATCH.CARGO_INFO_NO = RELEASE.CARGO_INFO_NO where a.TRUST_ID = #{id}
ORDER BY TBCI.CREATE_TIME
ORDER BY A.BUSINESS_NO

select *
from T_BUS_CARGO_SHIP
where TRUST_ID = #{trustId}  and CARGO_INFO_ID = #{cargoInfoId} and SHIP_VOYAGE_ITEM_ID = #{shipVoyageItemId}

