select TRUST_ID
from T_BUS_CARGO_INFO where TRUST_ID is not null  and id in

    #{id,jdbcType=BIGINT}

select TBH.ID,TBH.TON,TBH.QUANTITY,MC.FLOAT_TON from T_BUS_HANDOVERLIST TBH join T_BUS_CARGO_INFO TBCI on TBH.CARGO_INFO_ID = TBCI.ID join M_CARGO MC on TBCI.CARGO_CODE = MC.CARGO_CODE where TBH.LOAD_UNLOAD = '卸' and EXISTS ( select * from (
select #{cargoInfoId, jdbcType=BIGINT} as TMPID from dual
) a where a.TMPID = TBH.CARGO_INFO_ID ) group by TBH.ID, TBH.TON, TBH.QUANTITY, MC.FLOAT_TON

select TBH.ID,TBH.TON,TBH.QUANTITY,TBCI.CARGO_INFO_NO,TBH.TRUST_CARGO_ID
from T_BUS_HANDOVERLIST TBH
join T_BUS_CARGO_INFO TBCI on TBH.CARGO_INFO_ID = TBCI.ID
where TBH.LOAD_UNLOAD = #{loadUnload,jdbcType=VARCHAR}
and EXISTS (
select * from (

    select #{cargoInfoId, jdbcType=BIGINT} as TMPID
    from dual

) a where a.TMPID = TBH.CARGO_INFO_ID
)

select TBCI.ID,TBCI.CARGO_INFO_NO,TBCI.COMPANY_NAME,TBCI.COMPANY_ID,TBCI.CARGO_CODE FROM T_BUS_CARGO_INFO TBCI where EXISTS ( select * from (
select #{cargoInfoId, jdbcType=BIGINT} as TMPID from dual
) a where a.TMPID = TBCI.ID )
